import json

D = lambda i,t,s,e,n,c,nx: {"id":i,"text":t,"speaker":"我","avatar":"厂","score":s,"triggeredEvent":e,"historicalNote":n,"consequence":c,"nextActId":nx}
A = lambda i,t,k,tm,s,n,dls: {"id":i,"title":t,"isKeyAct":k,"timeMarker":tm,"sceneDescription":s,"npcDialogues":n,"dialogues":dls}
N = lambda sp,tx,av: {"speaker":sp,"text":tx,"avatar":av}

acts = []

# 10
acts.append(A("act-10","议会改革",False,"1832年",
"1832年，英国议会改革的呼声日益高涨。工业资产阶级要求获得更多的政治权利，工人阶级也在为普选权而斗争。作为曼彻斯特有影响力的工厂主，你在改革问题上的立场将产生重要影响。",
[N("议员格雷","先生，你们工业资产阶级是改革的重要力量。只要你们支持，议会改革就一定能成功。","格"),N("工人代表汤姆","老板，我们工人也要求选举权。没有政治权利，我们的利益就没有保障。","汤")],
[D("d1","我支持议会改革，工业资产阶级应该获得更多政治权利。",88,"你公开表示支持议会改革，还捐款支持改革运动。1832年议会改革法案通过后，工业资产阶级获得了更多议席，你也因此在政治上有了更大的发言权。","1832年议会改革是英国资产阶级民主进程中的重要事件。改革降低了选民的财产资格限制，增加了工业资产阶级的议席，使工业资产阶级开始参与国家政权。","支持改革，政治上位","act-11"),
D("d2","我反对改革，现在的制度挺好的，没必要改变。",65,"你公开反对议会改革，担心改革会威胁到有产阶级的利益。但改革的浪潮不可阻挡，法案最终还是通过了。你因为站在历史的对立面而声望受损。","1832年议会改革是历史发展的必然趋势。虽然遭到保守势力的反对，但在工业资产阶级和人民群众的压力下，改革最终取得了成功。","反对改革，声望受损","act-11"),
D("d3","我支持改革，但不能给工人选举权，那样会失控。",75,"你支持议会改革，但坚决反对给工人阶级选举权。你认为工人阶级还没有能力参与政治。最终改革法案只满足了资产阶级的要求，工人阶级被排除在外。","1832年议会改革是工业资产阶级对土地贵族的胜利，但工人阶级没有获得选举权。这导致了后来宪章运动的兴起，工人阶级开始独立争取政治权利。","支持改革，排斥工人","act-11"),
D("d4","我不仅支持改革，还支持工人的普选权要求。",92,"你不仅支持议会改革，还公开表示支持工人阶级的普选权要求。你的立场在资产阶级中引起了争议，但赢得了工人阶级的尊重。","19世纪初，英国工人阶级开始为争取普选权而斗争。虽然1832年改革没有满足工人的要求，但宪章运动等斗争推动了民主进程的发展。","支持普选，赢得尊重","act-11"),
D("d5","我不关心政治，只想管好自己的工厂。",70,"你对政治不感兴趣，只想专心经营工厂。虽然改革成功了，但与你关系不大，你仍然只是一个普通的工厂主。","工业革命时期，并不是所有的工厂主都关心政治。有些企业家专注于商业活动，对政治事务漠不关心。","不关心政治，专注经营","act-11"),
D("d6","我要竞选议员，直接参与政治决策。",82,"你决定竞选议员，凭借你的财富和影响力成功当选。从此你不仅是工厂主，还是议会议员，可以直接参与国家政策的制定。","随着工业革命的发展，工业资产阶级的经济实力不断增强，他们开始要求相应的政治权利。许多工厂主通过竞选进入议会，直接参与政治决策。","竞选议员，参政议政","act-11"),
D("d7","我要组织工厂主联合会，共同推动改革。",85,"你发起成立了工厂主联合会，联合工业资产阶级的力量共同推动议会改革。你们的集体行动对改革的成功起到了重要作用。","工业资产阶级为了维护自身利益，组织了各种政治团体和协会。这些组织在推动议会改革、制定经济政策等方面发挥了重要作用。","组织联合会，集体推动","act-11"),
D("d8","改革和我无关，我更关心关税和自由贸易问题。",78,"你对议会改革兴趣不大，更关心关税和自由贸易等经济问题。你积极游说政府降低关税，推动自由贸易政策。","工业资产阶级在经济上主张自由贸易，要求降低关税，取消贸易壁垒。这反映了工业资本主义发展的要求，也推动了英国经济政策的转变。","关注经济，推动贸易","act-11"),
D("d9","我担心改革会引发革命，还是保守一点好。",68,"你担心改革会引发社会革命，主张维持现状。但历史的潮流不可阻挡，改革还是如期而至。你的保守立场让你错失了参与政治的机会。","在社会变革时期，保守主义也是一种重要的思潮。但历史证明，顺应时代潮流的改革才能避免革命，实现社会的平稳转型。","保守立场，错失机会","act-11")]))

# 11
acts.append(A("act-11","铁路时代",False,"1825年",
"1825年，史蒂芬森设计的蒸汽机车在斯托克顿至达灵顿铁路上试车成功，标志着铁路时代的到来。曼彻斯特到利物浦的铁路正在规划中，你面临着一个重大的投资决策。",
[N("工程师史蒂芬森","先生，铁路是未来的方向。用火车运输货物，速度比马车快十倍，成本还低。","史"),N("保守商人托马斯","别听他的，火车太危险了，投资铁路就是把钱往水里扔！","托")],
[D("d1","我要大量投资铁路，这是改变时代的伟大事业。",95,"你果断投资了曼彻斯特至利物浦的铁路项目。1830年铁路开通后，获得了巨大的商业成功。你的投资翻了好几倍，还获得了铁路公司的董事席位。","1825年，英国建成了世界上第一条铁路——斯托克顿至达灵顿铁路。1830年，曼彻斯特至利物浦铁路通车，标志着铁路时代的开始。铁路的出现极大地改变了交通运输和经济发展。","投资铁路，巨额回报","act-12"),
D("d2","先投资一点试试，风险太大了不能全押上去。",82,"你谨慎地投资了一小笔钱。铁路开通后大获成功，你虽然赚了钱，但因为投资太少，收益有限。你有些后悔当初没有大胆一点。","铁路投资在19世纪的英国是一个巨大的商机。许多投资者因此致富，但也有一些人因为过于谨慎而错失良机。","小额投资，收益有限","act-12"),
D("d3","我要亲自去看火车试车，亲眼见证再决定。",88,"你专程前往斯托克顿，亲眼目睹了史蒂芬森的蒸汽机车试车。火车的震撼力让你坚定了投资的决心。你果断投入大笔资金，获得了丰厚回报。","1825年9月27日，史蒂芬森驾驶他设计的\"旅行者号\"蒸汽机车，在斯托克顿至达灵顿铁路上试车成功。这是人类历史上第一列用蒸汽机车牵引的列车。","亲自见证，坚定投资","act-12"),
D("d4","铁路太危险了，我才不投资呢，肯定会赔钱。",62,"你坚决不相信铁路能成功，拒绝了所有投资邀请。几年后，铁路大获成功，那些早期投资者都赚了大钱。你眼睁睁地看着机会从眼前溜走。","铁路在发展初期确实遇到了很多质疑和反对。但历史证明，铁路是19世纪最伟大的发明之一，彻底改变了人类的交通和生活方式。","拒绝投资，错失良机","act-11b"),
D("d5","我要投资生产机车和铁轨，给铁路建设提供设备。",90,"你没有直接投资铁路运营，而是投资了机车制造和铁轨生产。随着铁路建设热潮的兴起，你的工厂订单源源不断，赚得盆满钵满。","铁路建设带动了相关产业的发展。机车制造、钢铁生产、煤炭开采等行业都因为铁路的发展而蓬勃兴起，形成了新的产业链。","投资制造，订单不断","act-12"),
D("d6","我担心铁路会抢了我的货运生意，还是等等看吧。",72,"你担心铁路会影响你现有的运河货运生意，对铁路持观望态度。但铁路的优势是压倒性的，你的运河生意越来越差，最后不得不转型。","铁路的出现对传统的运河运输造成了巨大冲击。许多运河公司因为竞争不过铁路而倒闭，运输业的格局彻底改变了。","观望犹豫，生意受创","act-12"),
D("d7","我要联合其他工厂主一起投资，分散风险。",85,"你联合了几家有实力的工厂主，共同投资铁路建设。大家一起承担风险，也一起分享收益。铁路开通后，你们都获得了丰厚的回报。","铁路建设需要巨额资金，因此吸引了众多投资者。联合投资既可以分散风险，也可以集中力量办大事。","联合投资，共享收益","act-12"),
D("d8","我更看好运河运输，还是继续投资运河吧。",65,"你认为运河更可靠，继续投资运河运输。但铁路的发展速度远远超出了你的预期，运河运输很快就衰落了，你的投资打了水漂。","在铁路出现之前，运河是英国最重要的内陆运输方式。但铁路出现后，运河迅速衰落。这就是技术进步的残酷性——不进则退。","看好运河，投资失策","act-11b"),
D("d9","我要去美国考察，看看那边的铁路发展。",78,"你决定去美国考察铁路发展。美国的铁路建设方兴未艾，你看到了巨大的商机，决定在美国也投资一些铁路项目。","铁路革命很快从英国传播到美国和欧洲大陆。19世纪中后期，美国掀起了铁路建设热潮，铁路里程迅速超过英国，成为世界上铁路最发达的国家。","赴美考察，海外投资","act-12")]))

# 11b
acts.append(A("act-11b","反对铁路",False,"1830年",
"1830年，利物浦至曼彻斯特铁路正式通车，取得了巨大成功。火车的速度和效率让所有人震惊。而你当初因为保守而拒绝投资，现在眼睁睁看着别人发财，心中五味杂陈。",
[N("铁路公司董事布朗","看看吧，我早就说过铁路会成功。现在我们的股票涨了三倍，哈哈！","布"),N("朋友威廉","当初要是听我的一起投资就好了。不过现在还来得及，后面还有很多铁路项目。","威")],
[D("d1","亡羊补牢，犹未为晚。现在投资还来得及。",88,"你决定亡羊补牢，开始投资后续的铁路项目。虽然没有早期投资者赚得多，但也获得了不错的收益。更重要的是，你跟上了时代的步伐。","铁路建设是一个长期的过程，早期投资虽然利润最大，但风险也高。后来的投资者虽然利润少一些，但风险也更低，同样能获得不错的回报。","亡羊补牢，后来居上","act-12"),
D("d2","我才不眼红呢，我经营好自己的工厂就行了。",70,"你虽然有些后悔，但还是决定专注于自己的本业。你把工厂经营得很好，虽然没有发铁路财，但也过得很不错。","并不是所有人都适合投资新兴行业。专注于自己熟悉的领域，把本职工作做好，也是一种成功的策略。","专注本业，稳步发展","act-12"),
D("d3","我要把工厂卖掉，全部投入铁路。",68,"你头脑发热，把工厂卖掉全部投入铁路。正好赶上铁路投资泡沫破裂，股价暴跌，你损失惨重。","19世纪中期，英国出现了铁路投资狂热，形成了泡沫。泡沫破裂后，很多投资者血本无归。这提醒人们，投资需要理性，不能盲目跟风。","全部投入，损失惨重","act-12"),
D("d4","我要研究铁路技术，说不定能发明更好的东西。",85,"你开始研究铁路技术，还真的做出了一些改进发明。虽然没有投资铁路赚得多，但技术发明也让你获得了声望和专利收入。","工业革命时期，技术创新是最重要的驱动力。许多人通过研究新技术、申请专利获得了成功。技术发明的价值不亚于商业投资。","研究技术，专利收入","act-12"),
D("d5","我去欧洲大陆投资，那里铁路才刚刚起步。",82,"你把目光转向了欧洲大陆。法国、德国等国家的铁路建设才刚刚开始，还有很大的发展空间。你在那里的投资获得了丰厚的回报。","铁路革命很快从英国传播到欧洲大陆。19世纪中后期，欧洲各国纷纷开始大规模建设铁路，为投资者提供了新的机遇。","进军欧洲，开辟新局","act-12"),
D("d6","我不服气，我要发明比火车更好的交通工具。",76,"你不服气，决心研究新的交通工具。虽然最后没有成功，但这段经历让你对技术创新有了更深刻的理解。","创新精神是工业革命的灵魂。虽然不是所有的创新都能成功，但敢于尝试、勇于创新的精神是值得肯定的。","不服气，搞创新","act-12"),
D("d7","我要投资钢铁厂，铁路建设需要大量钢铁。",90,"你没有直接投资铁路运营，而是投资了钢铁厂。铁路建设需要大量钢铁，你的钢铁厂订单如雪片般飞来，赚得比铁路公司还多。","铁路建设带动了钢铁、煤炭、机械制造等相关产业的发展。有时候，间接投资于相关产业，可能比直接投资主流产业收益更高。","投资钢铁，订单爆满","act-12"),
D("d8","算了，命里有时终须有，命里无时莫强求。",65,"你认命了，觉得自己没有发财的命。你继续按部就班地经营工厂，虽然没有大富大贵，但也衣食无忧。","面对机遇，每个人的反应不同。有些人勇于冒险，有些人安于现状。不同的选择，不同的人生，没有绝对的对错。","安于现状，平淡度日","act-12"),
D("d9","我要创办一份铁路报纸，宣传铁路的好处。",78,"你创办了一份铁路主题的报纸，积极宣传铁路的好处。报纸办得很成功，不仅赚了广告费，还成了铁路行业的权威媒体。","信息传播也是重要的产业。新兴行业的发展需要舆论宣传，媒体在其中发挥了重要作用。创办行业媒体也是一种商机。","创办报纸，宣传铁路","act-12")]))

# 12
acts.append(A("act-12","工厂立法",False,"1833年",
"1833年，英国议会通过了《工厂法》，对童工的年龄和工作时间做出了限制。这是世界上第一部限制工厂工作时间的法律。作为工厂主，你对这部法律的态度将影响很多人的命运。",
[N("工厂主同行卡尔","这部法律简直是在干涉我们的权利！我们的工厂我们做主，凭什么让政府来管？","卡"),N("工人代表玛丽","感谢上帝，终于有法律保护我们的孩子了。我那可怜的儿子，才九岁就每天工作14个小时。","玛")],
[D("d1","我支持工厂法，早就该限制童工了。这是社会的进步。",90,"你公开表示支持工厂法，还主动在自己的工厂里提前实施。你的做法赢得了社会的赞誉，也为其他工厂主树立了榜样。","1833年英国议会通过的《工厂法》，是世界上第一部限制工厂工作时间和童工年龄的法律。它规定了童工的最低年龄和工作时间，还设立了工厂视察员制度。这是社会进步的重要标志。","支持工厂法，树立榜样","act-13"),
D("d2","我反对工厂法，这是对我们经营自由的干涉。",62,"你强烈反对工厂法，还联合其他工厂主一起抗议。但法律还是生效了，你因为拒不执行被罚款，还受到了舆论的谴责。","工厂法的通过遭到了很多工厂主的反对，他们认为这是对私有财产和经营自由的侵犯。但历史证明，保护工人权益是社会进步的必然要求。","反对工厂法，受到谴责","act-12b"),
D("d3","法律通过了就执行吧，尽量钻空子就是了。",70,"你虽然表面上执行工厂法，但想尽办法钻法律的空子。比如让童工在吃饭时间继续工作，或者伪造年龄证明。","工厂法实施初期，很多工厂主想方设法逃避法律监管。这说明仅靠法律是不够的，还需要严格的执法和社会监督。","阳奉阴违，钻空子","act-12b"),
D("d4","我要做得比法律要求的更好，彻底改善工人待遇。",92,"你决定不仅遵守法律，还要做得更好。你进一步缩短工时，提高工资，改善工作条件。你的工厂成为全英国工人待遇最好的工厂之一。","一些有远见的工厂主认识到，改善工人待遇不仅有利于工人，也有利于企业的长远发展。欧文在新拉纳克工厂的实验就是一个著名的例子。","超越法律，善待工人","act-13"),
D("d5","我要游说议会修改法律，让它更合理一些。",75,"你认为工厂法有些规定过于僵化，决定游说议会修改。你提出了一些建设性的意见，被议会采纳，让法律更加完善。","法律的制定是一个不断完善的过程。听取各方面的意见，包括工厂主的意见，有助于法律更加合理和可行。","游说议会，完善法律","act-13"),
D("d6","把工厂搬到没有工厂法的国家去，躲开监管。",65,"你决定把工厂搬到监管宽松的国家，躲开工厂法的约束。虽然短期来看成本降低了，但你也背上了剥削工人的恶名。","在工业革命时期，确实有一些资本家为了逃避监管，把工厂搬到劳工保护薄弱的地区。这反映了资本逐利的本性。","搬迁海外，逃避监管","act-12b"),
D("d7","我要建立工厂视察制度，主动接受监督。",85,"你在工厂内部建立了视察制度，主动邀请社会人士来工厂检查。你的坦诚和透明赢得了公众的信任，也提升了企业形象。","工厂法建立了视察员制度，负责监督法律的执行。一些有远见的工厂主主动配合视察，甚至邀请社会监督，这是企业社会责任的体现。","主动视察，接受监督","act-13"),
D("d8","缩短工时，同时提高效率，这样两不耽误。",88,"你想出了一个聪明的办法——通过改进技术和管理来提高效率，这样即使缩短工时也不会减少产量。工人高兴，你也没有损失，实现了双赢。","提高效率与改善工人待遇并不矛盾。实际上，善待工人往往能够提高工人的积极性和效率，反而有利于生产。这就是所谓的以人为本的管理。","提高效率，实现双赢","act-13"),
D("d9","工厂法和我没关系，我主要做贸易。",72,"你的主要业务是贸易，生产环节都外包出去了，所以工厂法对你影响不大。你继续做你的生意，对社会事务不太关心。","工业革命时期，社会分工越来越细。不同的人在不同的环节，对社会问题的感受和关注程度也不同。","与我无关，继续生意","act-13")]))

# 12b
acts.append(A("act-12b","规避监管",False,"1835年",
"你选择了规避工厂法的策略，想尽办法钻法律的空子。但纸终究包不住火，你的做法被人举报了。政府视察员要来检查，你面临着罚款和名誉扫地的风险。",
[N("律师亨利","老板，这次可能有点麻烦。如果视察员发现你违反工厂法，不仅要罚款，还可能被判刑。","亨"),N("工头罗伯特","老板，要不我们把童工藏起来，等视察员走了再说？","罗")],
[D("d1","我承认错误，接受处罚，以后一定遵守法律。",85,"你决定坦诚地承认错误，接受处罚，并且保证以后一定严格遵守法律。视察员对你的态度比较满意，处罚也相对较轻。","面对错误，坦诚承认并及时改正是最好的选择。逃避和抵赖只会让问题更加严重，最终付出更大的代价。","坦诚认错，接受处罚","act-13"),
D("d2","把童工藏起来，蒙混过关再说。",60,"你把童工藏了起来，试图蒙混过关。但视察员很有经验，很快就发现了破绽。你因为阻挠执法，受到了更严厉的处罚。","逃避监管和阻挠执法是违法行为，只会受到更严厉的处罚。在法律面前，耍小聪明是行不通的。","藏匿童工，处罚更重","act-13"),
D("d3","我要请最好的律师，和政府打官司。",68,"你请了最好的律师，准备和政府打官司。官司打了很久，虽然最后你赢了，但也花了很多钱，而且名誉受到了损害。","在法治社会，通过法律途径解决争议是公民的权利。但打官司费时费力，而且即使赢了，也可能输掉口碑。","请律师，打官司","act-13"),
D("d4","立刻整改，让视察员看到我的诚意。",88,"你立刻进行了全面整改，并且主动邀请视察员来检查。视察员看到你的整改措施很到位，也感受到了你的诚意，决定从轻处理。","及时整改、展现诚意是化解危机的有效方法。监管的目的不是惩罚，而是让企业守法经营。只要有改正的诚意，往往能得到宽大处理。","立刻整改，展现诚意","act-13"),
D("d5","我要行贿视察员，让他放我一马。",62,"你试图向视察员行贿，让他网开一面。没想到视察员刚正不阿，不仅拒绝了贿赂，还把你的行为也举报了。你罪加一等。","行贿是严重的违法行为。企图用贿赂逃避监管，只会让问题更加严重，最终受到更严厉的惩罚。","行贿失败，罪加一等","act-13"),
D("d6","我要向议会请愿，要求修改工厂法。",72,"你联合其他工厂主向议会请愿，要求修改工厂法中不合理的条款。请愿虽然没有达到预期效果，但也让立法者听到了你们的声音。","向议会请愿是公民的合法权利。通过合法渠道表达诉求，推动法律的完善，是民主社会的正常现象。","请愿修法，表达诉求","act-13"),
D("d7","把工厂卖了，再也不干这行了。",66,"你觉得这行越来越难做，决定把工厂卖掉转行。虽然退出了制造业，但你也摆脱了这些麻烦事。","面对严格的监管，一些企业主选择退出。这虽然是个人选择，但从社会角度看，监管的目的就是淘汰那些靠剥削工人牟利的企业。","卖掉工厂，转行退出","act-13"),
D("d8","我要彻底转型，做高科技产品，不再依赖廉价劳动力。",90,"这次事件让你认识到，靠剥削工人来赚钱是没有前途的。你决定彻底转型，投资新技术，做高附加值的产品。虽然转型很痛苦，但你找到了新的发展方向。","技术升级和产业转型是企业发展的必然趋势。随着劳工保护的加强和人力成本的上升，企业必须通过技术创新来提高竞争力。","彻底转型，技术升级","act-13"),
D("d9","我要去美国发展，那里监管宽松。",65,"你决定去美国发展，认为那里的监管更宽松。但你没想到，美国的工厂法很快也跟上来了，你不过是换了个地方继续面对同样的问题。","劳工权益保护是历史发展的必然趋势，不会因为地域的转移而改变。逃避不是办法，只有顺应历史潮流才是正道。","前往美国，继续面对","act-13")]))

# 13
acts.append(A("act-13","宪章运动",False,"1840年",
"1840年，宪章运动在英国蓬勃发展。工人阶级提出了六点要求，包括普选权、秘密投票、平等选区等。全国各地的工人纷纷签名请愿，声势浩大。作为工厂主，你对这场运动的态度至关重要。",
[N("宪章派领袖奥康纳","先生，普选权是我们的正当权利。工人阶级占人口的大多数，为什么不能有选举权？","奥"),N("保守派议员皮尔","这些工人简直是无法无天！必须坚决镇压，否则国将不国！","皮")],
[D("d1","我支持宪章运动，工人阶级应该有政治权利。",88,"你公开表示支持宪章运动，认为工人阶级理应获得选举权。你的立场在工厂主中引起了争议，但你认为民主是历史的潮流，不可阻挡。","宪章运动是19世纪英国工人阶级争取普选权的伟大运动。虽然当时没有取得完全成功，但它推动了民主进程，为后来的议会改革奠定了基础。","支持宪章，顺应潮流","act-14"),
D("d2","我坚决反对，工人懂什么政治，这是要造反！",60,"你强烈反对宪章运动，认为工人阶级没有能力参与政治。你还出钱支持政府镇压运动。但历史的潮流不可阻挡，民主最终还是到来了。","宪章运动遭到了英国政府的镇压。但工人阶级的斗争没有白费，经过长期的努力，普选权最终还是实现了。","反对宪章，阻挡潮流","act-13b"),
D("d3","我支持改革，但不能太激进，要循序渐进。",78,"你支持议会改革，但主张循序渐进，不能过于激进。你认为应该先给熟练工人和中产阶级选举权，然后再逐步扩大。","在民主进程中，渐进改革也是一种重要的思路。虽然激进派和渐进派的主张不同，但目标都是为了实现更完善的民主。","支持渐进，稳步推进","act-14"),
D("d4","我担心运动会引发革命，建议政府做出一些让步。",82,"你担心宪章运动会引发社会革命，建议政府做出一些让步，满足工人的部分要求。你认为适当的改革可以避免革命，维护社会稳定。","面对社会运动，是镇压还是改革，是统治阶级必须面对的选择。历史证明，适时的改革能够化解社会矛盾，避免革命的爆发。","建议让步，避免革命","act-14"),
D("d5","我不关心政治，只要工厂能正常运转就行。",70,"你对政治不感兴趣，只关心工厂的生产和利润。宪章运动对你的影响不大，你继续经营你的工厂，过着自己的日子。","并不是所有人都关心政治。在社会大变革中，有些人选择置身事外，专注于自己的生活和事业。","不关心政治，专注经营","act-14"),
D("d6","我要创办一份报纸，宣传我的政治主张。",80,"你创办了一份报纸，宣传自己的政治主张。报纸办得很成功，你也成了有影响力的政论家，在政治生活中发挥了作用。","工业革命时期，随着印刷业的发展和识字率的提高，报纸成为重要的舆论工具。许多有识之士通过办报来宣传自己的主张。","创办报纸，宣传主张","act-14"),
D("d7","我要和工人对话，了解他们的想法。",85,"你决定放下身段，和工人代表对话，了解他们的想法和诉求。通过对话，你对工人阶级有了更深的了解，也对社会问题有了新的认识。","对话比对抗更有建设性。不同阶级之间的沟通和理解，是化解社会矛盾、促进社会进步的重要途径。","深入对话，增进理解","act-14"),
D("d8","我支持普选，但担心工人会没收我的财产。",75,"你在原则上支持普选权，但也担心工人阶级掌权后会没收有产者的财产。你在民主和财产权之间感到矛盾和纠结。","民主与财产权的关系是一个经典的政治哲学问题。许多有产者既认同民主的理念，又担心民主会威胁到自己的财产。这种矛盾心理在历史上很常见。","支持普选，担忧财产","act-14"),
D("d9","我要移民美国，那里是民主的灯塔。",68,"你对英国的现状不满意，决定移民美国。你认为美国是一个更加民主和平等的国家。但你很快发现，美国也有它自己的问题。","19世纪，很多欧洲人移民美国，追求更美好的生活。美国被称为\"移民的熔炉\"，吸引了来自世界各地的人们。但美国的民主也有其局限性。","移民美国，追求民主","act-14")]))

# 13b
acts.append(A("act-13b","宪章派分裂",False,"1842年",
"宪章运动内部出现了分裂。道义派主张用和平请愿的方式争取权利，而暴力派则主张用武力推翻政府。与此同时，政府也在加强镇压。运动的前途未卜。",
[N("道义派领袖洛维特","我们必须坚持和平斗争的原则。暴力只会招来镇压，损害我们的事业。","洛"),N("暴力派领袖奥布赖恩","和平请愿根本没用！政府只听得懂大炮的声音！","奥")],
[D("d1","我支持道义派，和平斗争才是正确的道路。",88,"你公开表示支持道义派的和平斗争策略，还捐款支持他们的请愿活动。你认为通过和平、合法的方式争取权益，才是长久之计。","宪章运动内部确实存在道义派和暴力派的分歧。道义派主张用和平请愿的方式争取权利，代表了早期工人运动中的改良主义倾向。","支持道义，和平斗争","act-14"),
D("d2","我支持暴力派，不流血是换不来正义的。",62,"你同情暴力派的主张，暗中为他们提供资金和物资。但暴力起义很快就被政府镇压了，你也因为支持暴动而受到牵连。","宪章运动中的暴力派虽然有革命的激情，但缺乏正确的理论指导和严密的组织，最终不可避免地失败了。","支持暴力，遭受牵连","act-14"),
D("d3","两边都不支持，我还是明哲保身吧。",70,"你选择明哲保身，两边都不支持，也不反对。你继续经营自己的生意，对政治运动敬而远之。","在社会运动中，中间派也是一种常见的立场。有些人出于各种原因选择不站队，保持中立。","明哲保身，中立立场","act-14"),
D("d4","我要从中调解，让两派团结起来。",85,"你试图调解两派的分歧，呼吁大家团结起来，共同为工人阶级的利益而斗争。虽然调解没有完全成功，但你的努力得到了双方的尊重。","团结是工人运动取得胜利的关键。内部的分裂和内斗，往往是工人运动失败的重要原因。","调解分歧，呼吁团结","act-14"),
D("d5","我觉得他们都不对，我有自己的一套理论。",78,"你对宪章运动的两派都不满意，提出了自己的一套社会改革方案。虽然你的理论没有被广泛接受，但也吸引了一些追随者。","19世纪是各种社会思潮百花齐放的时代。除了马克思主义，还有各种空想社会主义、改良主义等思潮。","自创理论，另辟蹊径","act-14"),
D("d6","我要向政府告密，这样能得到奖赏。",60,"你向政府告密，出卖了宪章派的活动计划。你确实得到了政府的奖赏，但也永远背上了叛徒的骂名。","叛徒在任何时代都会受到鄙视。为了个人利益而出卖他人，是为人所不齿的行为。","告密求赏，身败名裂","act-14"),
D("d7","我要保护受到迫害的工人，尽我所能帮助他们。",90,"你利用自己的身份和财富，暗中保护受到迫害的工人活动家。你为他们提供藏身之处和经济援助，帮助他们渡过难关。","在工人运动遭受镇压的黑暗时期，一些有良知的有产者伸出了援手。他们的善举体现了人类的正义和良知。","保护工人，伸张正义","act-14"),
D("d8","我要去法国看看，那里的工人运动是什么样的。",76,"你决定去法国考察工人运动。法国的社会主义思潮让你大开眼界，你对工人运动有了更深入的认识。","工人运动是国际性的。各国工人运动相互影响、相互促进。法国是社会主义思潮的重要发源地，对整个欧洲都有重要影响。","考察法国，开阔眼界","act-14"),
D("d9","宪章运动成不了气候，我还是关心经济危机吧。",72,"你认为宪章运动成不了气候，不值得关注。你更关心即将到来的经济危机，忙着为自己的企业做准备。","政治运动和经济危机往往是交织在一起的。经济危机会加剧社会矛盾，推动政治运动的发展。","不关心政治，关注经济","act-14")]))

print(f"第四组生成完成，共 {len(acts)} 幕")

with open("group4.json", "w", encoding="utf-8") as f:
    json.dump(acts, f, ensure_ascii=False, indent=2)

